/** Lookup: normalisierter Ortsname → Bürgermeister */
const _bmIndex = new Map<string, KommunalPolitiker>();
for (const bm of BUERGERMEISTER_AUTO) {
  const key = bm.ort.toLowerCase().replace(/\s*\(.*?\)\s*/g, '').trim();
  if (!_bmIndex.has(key)) _bmIndex.set(key, bm);
}

export function findBuergermeister(cityName: string): KommunalPolitiker | undefined {
  const key = cityName.toLowerCase().replace(/\s*\(.*?\)\s*/g, '').trim();
  return _bmIndex.get(key);
}

/** Lookup: AGS (5-stellig, ggf. 3 für Kreise) → Landrat */
const _lrIndex = new Map<string, KommunalPolitiker>();
for (const lr of LANDRAETE_AUTO) {
  if (lr.ags) _lrIndex.set(lr.ags, lr);
  const key = lr.ort.toLowerCase().replace(/\s*\(.*?\)\s*/g, '').trim();
  if (!_lrIndex.has(key)) _lrIndex.set(key, lr);
}

export function findLandrat(kreisName: string): KommunalPolitiker | undefined {
  const key = kreisName.toLowerCase().replace(/\s*\(.*?\)\s*/g, '').trim();
  return _lrIndex.get(key);
}

export function findLandratByAgs(ags: string): KommunalPolitiker | undefined {
  return _lrIndex.get(ags);
}
